#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e3 + 5;
int n, k, a[MAXN], ans = 0, sum[MAXN];
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	n = read(), k = read();
	for (int i = 1; i <= n; ++i)
	{
		a[i] = read();
	}
	sort(a + 1, a + n + 1);
	for (int i = 1; i <= n; ++i)
	{
		sum[i] = sum[i - 1] + a[i];
	}
	int l = 1, r = 1;
	while (r <= n)
	{
		if (a[r] - a[l] > k)
		{
			++l;
		}
		else
		{
			ans = max(ans, sum[r] - sum[l - 1]);
			++r;
		}
	}
	write(ans);
	return false;
}
